import{_ as o,o as r,c as t,ag as a}from"./chunks/framework.BbyMWZAR.js";const p=JSON.parse('{"title":"性能优化、内存泄漏与安全","description":"","frontmatter":{"title":"性能优化、内存泄漏与安全","difficulty":"hard","tags":["性能优化","内存泄漏","安全"],"estimate":30},"headers":[],"relativePath":"domains/nodejs/qa/qa-10-performance-security.md","filePath":"domains/nodejs/qa/qa-10-performance-security.md","lastUpdated":1783504823000}'),l={name:"domains/nodejs/qa/qa-10-performance-security.md"};function i(n,e,s,d,c,h){return r(),t("div",null,[...e[0]||(e[0]=[a('<h1 id="问答-10-高级-综合-性能优化、内存泄漏与安全" tabindex="-1">问答 10（高级/综合）：性能优化、内存泄漏与安全 <a class="header-anchor" href="#问答-10-高级-综合-性能优化、内存泄漏与安全" aria-label="Permalink to &quot;问答 10（高级/综合）：性能优化、内存泄漏与安全&quot;">​</a></h1><h2 id="题目" tabindex="-1">题目 <a class="header-anchor" href="#题目" aria-label="Permalink to &quot;题目&quot;">​</a></h2><p>线上 Node.js 服务变慢或内存持续增长，你会如何排查？常见内存泄漏原因有哪些？Node 服务有哪些常见安全风险和防护手段？</p><h2 id="参考答案" tabindex="-1">参考答案 <a class="header-anchor" href="#参考答案" aria-label="Permalink to &quot;参考答案&quot;">​</a></h2><p><strong>性能变慢排查思路</strong></p><ol><li>先分清瓶颈：CPU、内存、I/O、还是事件循环阻塞。</li><li><strong>事件循环延迟</strong>：<code>perf_hooks.monitorEventLoopDelay</code>，延迟高说明有长同步任务或 CPU 密集。</li><li><strong>CPU 火焰图</strong>：<code>node --prof</code>、<code>clinic flame</code>、<code>0x</code> 找热点函数。</li><li><strong>内存</strong>：<code>process.memoryUsage()</code>（rss/heapUsed/external）、堆快照（<code>--inspect</code> + Chrome DevTools / heapdump）对比多次快照找持续增长的对象。</li><li><strong>I/O/下游</strong>：DB 慢查询、连接池耗尽、第三方超时、缺少缓存。</li></ol><p><strong>常见内存泄漏原因</strong></p><ul><li>全局变量/模块级缓存无限增长（Map 只增不删）。</li><li>未移除的事件监听器（EventEmitter 累积，超过默认 10 个还会警告）。</li><li>闭包持有大对象。</li><li>未清除的定时器（<code>setInterval</code> 引用外部对象）。</li><li>未关闭的流/句柄/连接。</li></ul><p><strong>常见安全风险与防护</strong></p><ul><li><strong>注入</strong>：SQL 注入（用参数化查询/ORM）、命令注入（避免 <code>exec</code> 拼接用户输入，用 <code>execFile</code>/<code>spawn</code> 传数组）。</li><li><strong>XSS/CSRF</strong>（配合前端）：输出转义、CSP、CSRF token。</li><li><strong>DoS</strong>：限制 body 大小、请求速率限流、正则回溯（ReDoS）用安全正则。</li><li><strong>依赖漏洞</strong>：<code>npm audit</code>、锁定版本、及时升级。</li><li><strong>敏感信息</strong>：不硬编码密钥（用环境变量/密钥管理），关闭详细错误堆栈对外暴露，设置安全响应头（helmet）。</li><li><strong>原型污染</strong>：谨慎合并用户输入对象。</li></ul><h2 id="追问-1-如何定位「未移除的事件监听器」导致的泄漏" tabindex="-1">追问 1：如何定位「未移除的事件监听器」导致的泄漏？ <a class="header-anchor" href="#追问-1-如何定位「未移除的事件监听器」导致的泄漏" aria-label="Permalink to &quot;追问 1：如何定位「未移除的事件监听器」导致的泄漏？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>现象：控制台出现 <code>MaxListenersExceededWarning</code>，或堆快照里某 EventEmitter 的 listeners 数组持续变大。</li><li>定位：给可疑 emitter 打印 <code>emitter.listenerCount(event)</code>；用堆快照对比找到 retained size 增长的闭包/监听器。</li><li>修复：在合适时机 <code>removeListener</code>/<code>off</code>；对一次性用 <code>once</code>；避免在每次请求里给长生命周期对象（如全局 emitter、DB client）重复 <code>on</code>。</li></ul><h2 id="追问-2-什么是-redos-怎么避免" tabindex="-1">追问 2：什么是 ReDoS？怎么避免？ <a class="header-anchor" href="#追问-2-什么是-redos-怎么避免" aria-label="Permalink to &quot;追问 2：什么是 ReDoS？怎么避免？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>ReDoS（正则拒绝服务）：某些正则在特定输入下会发生<strong>灾难性回溯</strong>，时间复杂度指数级，一个恶意字符串就能让单核 CPU 打满、阻塞事件循环。</li><li>危险模式：嵌套量词如 <code>(a+)+</code>、<code>(a|a)*</code>、重叠的可选组。</li><li>避免：简化正则、避免嵌套量词、用非回溯/线性引擎（如 RE2）、对用户输入长度做限制、用工具（safe-regex）检测。</li></ul><h2 id="追问-3-node-服务优雅关闭-graceful-shutdown-为什么重要-怎么实现" tabindex="-1">追问 3：Node 服务优雅关闭（graceful shutdown）为什么重要？怎么实现？ <a class="header-anchor" href="#追问-3-node-服务优雅关闭-graceful-shutdown-为什么重要-怎么实现" aria-label="Permalink to &quot;追问 3：Node 服务优雅关闭（graceful shutdown）为什么重要？怎么实现？&quot;">​</a></h2><p><strong>答</strong>：</p><ul><li>重要性：部署/扩缩容时进程会收到 <code>SIGTERM</code>，若直接退出会中断正在处理的请求、丢失数据、连接未释放，用户看到 502。</li><li>实现要点： <ol><li>监听 <code>SIGTERM</code>/<code>SIGINT</code>；</li><li><code>server.close()</code> 停止接收新连接，但让在途请求完成；</li><li>关闭数据库连接池、消息队列、定时器；</li><li>设置超时兜底：若超过 N 秒仍未关完，强制 <code>process.exit(1)</code>；</li><li>健康检查配合：先让负载均衡摘流（readiness 置为 false）再关闭。</li></ol></li></ul><h2 id="参考资料" tabindex="-1">参考资料 <a class="header-anchor" href="#参考资料" aria-label="Permalink to &quot;参考资料&quot;">​</a></h2><blockquote><p>深入阅读请从标注 <strong>首选</strong> 的来源开始；本领域完整索引见 <a href="/engineer/handbook/domains/nodejs/RESOURCES">Node.js 参考资料</a>。</p></blockquote><ul><li><strong>首选</strong> — <a href="https://nodejs.org/api/perf_hooks.html" target="_blank" rel="noreferrer">Node.js: perf_hooks</a>：<code>monitorEventLoopDelay</code> 与事件循环延迟诊断。</li><li><a href="https://nodejs.org/api/report.html" target="_blank" rel="noreferrer">Node.js: Diagnostic reports</a>：崩溃/高内存时自动生成堆栈与资源快照。</li><li><a href="https://nodejs.org/en/learn/getting-started/security-best-practices" target="_blank" rel="noreferrer">Node.js: Security Best Practices</a>：依赖审计、输入校验与常见攻击防护清单。</li></ul>',22)])])}const u=o(l,[["render",i]]);export{p as __pageData,u as default};
